<?php
declare(strict_types=1);

function communication_thread(int $id):array{$q=db()->prepare("SELECT t.*,c.first_name,c.last_name,c.email contact_email,o.title opportunity_title,COALESCE(NULLIF(u.display_name,''),u.username) assigned_name FROM email_threads t JOIN contacts c ON c.id=t.contact_id LEFT JOIN opportunities o ON o.id=t.opportunity_id LEFT JOIN users u ON u.id=t.assigned_user_id WHERE t.id=?");$q->execute([$id]);$t=$q->fetch();if(!$t||contact_access((int)$t['contact_id'])==='hidden'){http_response_code(404);exit('Conversation not found');}return $t;}
function communication_merge(string $text,array $contact):string{$map=['{{first_name}}'=>$contact['first_name']??'','{{last_name}}'=>$contact['last_name']??'','{{full_name}}'=>trim(($contact['first_name']??'').' '.($contact['last_name']??'')),'{{company}}'=>$contact['company']??'','{{email}}'=>$contact['email']??''];return strtr($text,$map);}
function communication_send(int $threadId,string $subject,string $body,int $userId):void{$thread=communication_thread($threadId);if(!filter_var($thread['contact_email'],FILTER_VALIDATE_EMAIL))throw new RuntimeException('This contact does not have a valid email address.');$signature=db()->prepare('SELECT signature_text FROM user_email_signatures WHERE user_id=?');$signature->execute([$userId]);$sig=trim((string)$signature->fetchColumn());if($sig!=='')$body=rtrim($body)."\n\n".$sig;$from=app_setting('mail_from_address','notifications@'.(parse_url((string)config('url'),PHP_URL_HOST)?:'localhost'));db()->prepare("INSERT INTO email_messages(thread_id,direction,from_address,to_address,subject,body_text,delivery_status,sent_by) VALUES(?,'outbound',?,?,?,?,'queued',?)")->execute([$threadId,$from,$thread['contact_email'],$subject,$body,$userId]);$messageId=(int)db()->lastInsertId();try{send_mail($thread['contact_email'],$subject,$body);db()->prepare("UPDATE email_messages SET delivery_status='sent',sent_at=NOW() WHERE id=?")->execute([$messageId]);db()->prepare('UPDATE email_threads SET subject=?,last_message_at=NOW(),status=\'open\' WHERE id=?')->execute([$subject,$threadId]);audit('send','email_message',$messageId,['thread_id'=>$threadId,'contact_id'=>$thread['contact_id']]);}catch(Throwable $e){db()->prepare("UPDATE email_messages SET delivery_status='failed',error_message=? WHERE id=?")->execute([mb_strimwidth($e->getMessage(),0,1000),$messageId]);throw $e;}}

if($path==='/communications'){
 require_permission('communications.view');$scope=(string)($_GET['scope']??'mine');$search=trim((string)($_GET['q']??''));$sql="SELECT t.*,c.first_name,c.last_name,c.email,COALESCE(NULLIF(u.display_name,''),u.username) assigned_name FROM email_threads t JOIN contacts c ON c.id=t.contact_id LEFT JOIN users u ON u.id=t.assigned_user_id WHERE 1";$args=[];if($scope==='mine'){$sql.=' AND t.assigned_user_id=?';$args[]=user()['id'];}elseif($scope==='unassigned')$sql.=' AND t.assigned_user_id IS NULL';if($search!==''){$sql.=' AND (t.subject LIKE ? OR c.first_name LIKE ? OR c.last_name LIKE ? OR c.email LIKE ?)';$like='%'.$search.'%';array_push($args,$like,$like,$like,$like);}$sql.=' ORDER BY COALESCE(t.last_message_at,t.created_at) DESC LIMIT 500';$q=db()->prepare($sql);$q->execute($args);$rows=array_values(array_filter($q->fetchAll(),fn($r)=>contact_access((int)$r['contact_id'])!=='hidden'));layout('Conversations',function()use($rows,$scope,$search){?><div class="actions"><h1 style="margin:0">Conversations</h1><span class="spacer"></span><?php if(can('communications.edit')):?><a class="btn secondary" href="/communications/templates">Templates & signature</a><a class="btn" href="/communications/compose">Compose</a><?php endif?></div><form class="card form-grid" method="get"><label>Search<input name="q" value="<?=e($search)?>"></label><label>Inbox<select name="scope"><option value="mine" <?=$scope==='mine'?'selected':''?>>Assigned to me</option><option value="all" <?=$scope==='all'?'selected':''?>>All visible</option><option value="unassigned" <?=$scope==='unassigned'?'selected':''?>>Unassigned</option></select></label><button>Apply</button></form><div class="card"><table><thead><tr><th>Contact</th><th>Subject</th><th>Assigned</th><th>Last message</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r):?><tr class="<?=$r['unread_count']?'unread-row':''?>"><td><a href="/contacts/<?=$r['contact_id']?>"><?=e($r['first_name'].' '.$r['last_name'])?></a><br><span class="muted"><?=e($r['email'])?></span></td><td><a href="/communications/<?=$r['id']?>"><?=e($r['subject'])?></a><?=$r['unread_count']?' <strong>('.(int)$r['unread_count'].')</strong>':''?></td><td><?=e($r['assigned_name']?:'Unassigned')?></td><td><?=e($r['last_message_at']?:$r['created_at'])?></td><td><?=e($r['status'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit;
}
if($path==='/communications/compose'){
 require_permission('communications.edit');$contactId=(int)($_GET['contact_id']??post('contact_id'));if($method==='POST'){verify_csrf();$c=contact_row($contactId);$subject=trim((string)post('subject'));$body=trim((string)post('body'));if($subject===''||$body===''){flash('error','Subject and message are required.');}else{db()->prepare('INSERT INTO email_threads(contact_id,opportunity_id,subject,assigned_user_id,last_message_at,created_by) VALUES(?,?,?,?,NOW(),?)')->execute([$contactId,post('opportunity_id')?:null,$subject,user()['id'],user()['id']]);$id=(int)db()->lastInsertId();try{communication_send($id,$subject,communication_merge($body,$c),(int)user()['id']);flash('success','Email sent.');redirect('/communications/'.$id);}catch(Throwable $e){flash('error',$e->getMessage());redirect('/communications/'.$id);}}}$contacts=db()->query("SELECT id,CONCAT(first_name,' ',last_name) name,email FROM contacts WHERE active=1 AND email IS NOT NULL AND email<>'' ORDER BY first_name,last_name LIMIT 2000")->fetchAll();$templates=db()->prepare('SELECT * FROM email_templates WHERE active=1 AND (shared=1 OR owner_user_id=?) ORDER BY name');$templates->execute([user()['id']]);$opps=$contactId?db()->prepare('SELECT o.id,o.title FROM opportunities o JOIN opportunity_contacts oc ON oc.opportunity_id=o.id WHERE oc.contact_id=? AND o.active=1 ORDER BY o.created_at DESC'):null;if($opps)$opps->execute([$contactId]);layout('Compose email',function()use($contacts,$templates,$contactId,$opps){?><h1>Compose email</h1><form class="card" method="post" id="email-compose"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Contact<select name="contact_id" required><option value="">Choose contact…</option><?php foreach($contacts as $c)if(contact_access((int)$c['id'])!=='hidden'):?><option value="<?=$c['id']?>" <?=$contactId===$c['id']?'selected':''?>><?=e($c['name'].' · '.$c['email'])?></option><?php endif?></select></label><?php if($opps):?><label>Opportunity<select name="opportunity_id"><option value="">None</option><?php foreach($opps->fetchAll() as $o):?><option value="<?=$o['id']?>"><?=e($o['title'])?></option><?php endforeach?></select></label><?php endif?><label>Template<select id="email-template"><option value="">No template</option><?php foreach($templates->fetchAll() as $t):?><option value="<?=$t['id']?>" data-subject="<?=e($t['subject'])?>" data-body="<?=e($t['body_text'])?>"><?=e($t['name'])?></option><?php endforeach?></select></label><label>Subject<input name="subject" required></label><label>Message<textarea name="body" rows="14" required></textarea></label><p class="muted">Merge fields: {{first_name}}, {{last_name}}, {{full_name}}, {{company}}, {{email}}</p><button>Send email</button></form><script>document.querySelector('#email-template').onchange=e=>{const o=e.target.selectedOptions[0];if(o.value){document.querySelector('[name=subject]').value=o.dataset.subject;document.querySelector('[name=body]').value=o.dataset.body}}</script><?php });exit;
}
if($path==='/communications/templates'){
 require_permission('communications.edit');if($method==='POST'){verify_csrf();$action=(string)post('action');if($action==='signature'){db()->prepare('INSERT INTO user_email_signatures(user_id,signature_text) VALUES(?,?) ON DUPLICATE KEY UPDATE signature_text=VALUES(signature_text)')->execute([user()['id'],trim((string)post('signature'))]);}elseif($action==='template'){db()->prepare('INSERT INTO email_templates(name,subject,body_text,owner_user_id,shared,created_by,updated_by) VALUES(?,?,?,?,?,?,?)')->execute([trim((string)post('name')),trim((string)post('subject')),trim((string)post('body')),user()['id'],(user()['is_admin']??false)&&post('shared')?1:0,user()['id'],user()['id']]);}elseif($action==='delete')db()->prepare('UPDATE email_templates SET active=0 WHERE id=? AND (owner_user_id=? OR ?=1)')->execute([(int)post('template_id'),user()['id'],user()['is_admin']?1:0]);audit($action,'email_template');flash('success','Email settings saved.');redirect('/communications/templates');}$sig=db()->prepare('SELECT signature_text FROM user_email_signatures WHERE user_id=?');$sig->execute([user()['id']]);$templates=db()->prepare('SELECT * FROM email_templates WHERE active=1 AND (shared=1 OR owner_user_id=?) ORDER BY shared DESC,name');$templates->execute([user()['id']]);layout('Email templates and signature',function()use($sig,$templates){?><h1>Email templates & signature</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="signature"><h2>My signature</h2><textarea name="signature" rows="6"><?=e($sig->fetchColumn()?:'')?></textarea><button>Save signature</button></form><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="template"><h2>New template</h2><label>Name<input name="name" required></label><label>Subject<input name="subject" required></label><label>Message<textarea name="body" rows="10" required></textarea></label><?php if(user()['is_admin']):?><label><input type="checkbox" name="shared" value="1" style="width:auto"> Share with all users</label><?php endif?><button>Create template</button></form><div class="card"><h2>Available templates</h2><table><?php foreach($templates->fetchAll() as $t):?><tr><td><strong><?=e($t['name'])?></strong><br><?=e($t['subject'])?></td><td><?=$t['shared']?'Shared':'Private'?></td><td><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="template_id" value="<?=$t['id']?>"><button class="danger compact">Archive</button></form></td></tr><?php endforeach?></table></div><?php });exit;
}
if(preg_match('#^/communications/(\d+)$#',$path,$m)){
 require_permission('communications.view');$thread=communication_thread((int)$m[1]);if($method==='POST'){verify_csrf();require_permission('communications.edit');$action=(string)post('action');if($action==='reply')try{communication_send((int)$thread['id'],$thread['subject'],trim((string)post('body')),(int)user()['id']);flash('success','Reply sent.');}catch(Throwable $e){flash('error',$e->getMessage());}elseif($action==='assign')db()->prepare('UPDATE email_threads SET assigned_user_id=? WHERE id=?')->execute([post('assigned_user_id')?:null,$thread['id']]);elseif($action==='status')db()->prepare('UPDATE email_threads SET status=? WHERE id=?')->execute([post('status')==='closed'?'closed':'open',$thread['id']]);redirect('/communications/'.$thread['id']);}db()->prepare('UPDATE email_threads SET unread_count=0 WHERE id=?')->execute([$thread['id']]);$q=db()->prepare('SELECT m.*,COALESCE(NULLIF(u.display_name,\'\'),u.username) sender_name FROM email_messages m LEFT JOIN users u ON u.id=m.sent_by WHERE m.thread_id=? ORDER BY m.created_at');$q->execute([$thread['id']]);$messages=$q->fetchAll();$users=db()->query('SELECT id,COALESCE(NULLIF(display_name,\'\'),username) name FROM users WHERE active=1 ORDER BY name')->fetchAll();layout($thread['subject'],function()use($thread,$messages,$users){?><div class="actions"><h1 style="margin:0"><?=e($thread['subject'])?></h1><span class="spacer"></span><a class="btn secondary" href="/contacts/<?=$thread['contact_id']?>"><?=e($thread['first_name'].' '.$thread['last_name'])?></a></div><div class="card form-grid"><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="assign"><label>Assigned to<select name="assigned_user_id" onchange="this.form.submit()"><option value="">Unassigned</option><?php foreach($users as $u):?><option value="<?=$u['id']?>" <?=$thread['assigned_user_id']==$u['id']?'selected':''?>><?=e($u['name'])?></option><?php endforeach?></select></label></form><form method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="status"><label>Status<select name="status" onchange="this.form.submit()"><option value="open">Open</option><option value="closed" <?=$thread['status']==='closed'?'selected':''?>>Closed</option></select></label></form><?php if($thread['opportunity_title']):?><p><strong>Opportunity:</strong> <?=e($thread['opportunity_title'])?></p><?php endif?></div><div class="conversation-thread"><?php foreach($messages as $msg):?><article class="card message <?=$msg['direction']?>"><div class="actions"><strong><?=$msg['direction']==='outbound'?'Sent by '.e($msg['sender_name']?:'System'):'Received from '.e($msg['from_address'])?></strong><span class="spacer"></span><span class="muted"><?=e($msg['sent_at']?:$msg['received_at']?:$msg['created_at'])?> · <?=e($msg['delivery_status'])?></span></div><p><?=nl2br(e($msg['body_text']))?></p><?php if($msg['error_message']):?><div class="flash error"><?=e($msg['error_message'])?></div><?php endif?></article><?php endforeach?></div><?php if(can('communications.edit')):?><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="reply"><label>Reply<textarea name="body" rows="8" required></textarea></label><button>Send reply</button></form><?php endif?><?php });exit;
}
